using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _sut = new OrderService();
    }

    // ── CreateOrder: Happy path ──────────────────────────────────────

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 2 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(19.98m, order.Total);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(1, order.Items.Count);
        Assert.AreEqual("Widget", order.Items[0].ProductName);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsSumOfAllItemTotals()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 25.50m, Quantity = 1 },
            new() { ProductName = "Gizmo", Price = 5.00m, Quantity = 4 }
        };

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert — (10*2) + (25.50*1) + (5*4) = 20 + 25.50 + 20 = 65.50
        Assert.AreEqual(65.50m, order.Total);
        Assert.AreEqual(3, order.Items.Count);
    }

    [TestMethod]
    [DataRow(10.00, 1, 10.00, DisplayName = "Single unit at $10")]
    [DataRow(5.50, 3, 16.50, DisplayName = "Three units at $5.50")]
    [DataRow(0.01, 100, 1.00, DisplayName = "100 units at $0.01")]
    [DataRow(99.99, 1, 99.99, DisplayName = "Single unit at $99.99")]
    public void CreateOrder_VariousPricesAndQuantities_CalculatesCorrectTotal(
        double price, int quantity, double expectedTotal)
    {
        // Arrange — DataRow requires compile-time constants, so use double → decimal
        var items = new List<OrderItem>
        {
            new() { ProductName = "TestProduct", Price = (decimal)price, Quantity = quantity }
        };

        // Act
        var order = _sut.CreateOrder("cust-param", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsNonEmptyId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        var before = DateTime.UtcNow;

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before, $"CreatedAt {order.CreatedAt} should be >= {before}");
        Assert.IsTrue(order.CreatedAt <= after, $"CreatedAt {order.CreatedAt} should be <= {after}");
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_GeneratesUniqueIds()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_OrderIsRetrievableById()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var created = _sut.CreateOrder("cust-1", items);
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(created, retrieved);
    }

    // ── CreateOrder: Error cases ─────────────────────────────────────

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", items));
        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // ── GetOrder ─────────────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_ExistingOrderId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        var created = _sut.CreateOrder("cust-1", items);

        // Act
        var result = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(created.Id, result.Id);
        Assert.AreEqual("cust-1", result.CustomerId);
        Assert.AreEqual(5.00m, result.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_MultipleOrders_ReturnsCorrectOne()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "Gadget", Price = 20.00m, Quantity = 1 }
        };
        var order1 = _sut.CreateOrder("cust-1", items1);
        var order2 = _sut.CreateOrder("cust-2", items2);

        // Act
        var result = _sut.GetOrder(order2.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(order2.Id, result.Id);
        Assert.AreEqual(20.00m, result.Total);
    }

    // ── GetOrdersByCustomer ──────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOneOrder_ReturnsSingleOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-1", items);

        // Act
        var result = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual("cust-1", result[0].CustomerId);
        Assert.AreEqual(5.00m, result[0].Total);
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithMultipleOrders_ReturnsAllMatchingOrders()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "Gadget", Price = 20.00m, Quantity = 2 }
        };
        _sut.CreateOrder("cust-1", items1);
        _sut.CreateOrder("cust-1", items2);

        // Act
        var result = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
        Assert.AreEqual(10.00m, result[0].Total);
        Assert.AreEqual(40.00m, result[1].Total);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrdersForCustomer_ReturnsEmptyList()
    {
        // Arrange — create an order for a different customer
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-other", items);

        // Act
        var result = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MixedCustomers_ReturnsOnlyMatchingCustomer()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-2", items);
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-3", items);

        // Act
        var result = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrdersExist_ReturnsEmptyList()
    {
        // Act
        var result = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(0, result.Count);
    }
}

